/*
 * CUDA Hybrid Programming Example
 * Demonstrates CPU-GPU collaboration with memory management and kernel execution
 * Compile: nvcc -o hybrid_program hybrid_cuda.cu
 */

#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define N 1024 * 1024 // 1 million elements
#define THREADS_PER_BLOCK 256
#define BLOCKS (N + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK

// GPU Kernel: Data-parallel computation
// Each thread processes one element
__global__ void parallel_process_kernel(float *data, float *results, int n) {
 // Calculate global thread index
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 // Boundary check
 if (idx < n) {
 // Compute: f(x) = x^2 + 2*sin(x)
 // This represents a typical data-parallel operation
 float x = data[idx];
 results[idx] = (x * x) + (2.0f * sinf(x));
 }
}

// GPU Kernel: Reduction operation (sum)
__global__ void reduction_kernel(float *data, float *result, int n) {
 __shared__ float shared_data[THREADS_PER_BLOCK];

 int tid = threadIdx.x;
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 // Load data into shared memory
 if (idx < n) {
 shared_data[tid] = data[idx];
 } else {
 shared_data[tid] = 0.0f;
 }
 __syncthreads();

 // Parallel reduction in shared memory
 for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
 if (tid < stride) {
 shared_data[tid] += shared_data[tid + stride];
 }
 __syncthreads();
 }

 // Write block result to global memory
 if (tid == 0) {
 result[blockIdx.x] = shared_data[0];
 }
}

void initialize_host_data(float *data, int n) {
 for (int i = 0; i < n; i++) {
 data[i] = (float)rand() / RAND_MAX * 10.0f;
 }
}

int main() {
 float *h_data, *h_results, *h_reduction_result;
 float *d_data, *d_results, *d_reduction_result;
 size_t size = N * sizeof(float);

 printf("================================================\n");
 printf(" CUDA Hybrid CPU-GPU Programming Example\n");
 printf("================================================\n\n");

 // ================================================
 // STEP 1: CPU - Allocate and initialize host memory
 // ================================================
 printf("[CPU] Allocating host memory...\n");
 h_data = (float*)malloc(size);
 h_results = (float*)malloc(size);
 h_reduction_result = (float*)malloc(BLOCKS * sizeof(float));

 printf("[CPU] Initializing data...\n");
 initialize_host_data(h_data, N);

 // ================================================
 // STEP 2: CPU -> GPU - Allocate device memory
 // ================================================
 printf("[CPU->GPU] Allocating device memory...\n");
 cudaMalloc((void**)&d_data, size);
 cudaMalloc((void**)&d_results, size);
 cudaMalloc((void**)&d_reduction_result, BLOCKS * sizeof(float));

 // ================================================
 // STEP 3: CPU -> GPU - Transfer input data
 // ================================================
 printf("[CPU->GPU] Copying data to GPU (%.2f MB)...\n", size / (1024.0f * 1024.0f));
 cudaMemcpy(d_data, h_data, size, cudaMemcpyHostToDevice);

 // ================================================
 // STEP 4: GPU - Launch parallel kernel
 // ================================================
 printf("[GPU] Launching parallel kernel...\n");
 printf(" Grid size: %d blocks, %d threads/block\n", BLOCKS, THREADS_PER_BLOCK);

 cudaEvent_t start, stop;
 cudaEventCreate(&start);
 cudaEventCreate(&stop);
 cudaEventRecord(start);

 parallel_process_kernel<<<BLOCKS, THREADS_PER_BLOCK>>>(d_data, d_results, N);

 cudaEventRecord(stop);
 cudaEventSynchronize(stop);

 float kernel_time;
 cudaEventElapsedTime(&kernel_time, start, stop);
 printf("[GPU] Kernel execution time: %.3f ms\n", kernel_time);

 // ================================================
 // STEP 5: GPU - Perform reduction
 // ================================================
 printf("[GPU] Performing parallel reduction...\n");
 reduction_kernel<<<BLOCKS, THREADS_PER_BLOCK>>>(d_results, d_reduction_result, N);

 // ================================================
 // STEP 6: GPU -> CPU - Transfer results back
 // ================================================
 printf("[GPU->CPU] Copying results back to host...\n");
 cudaMemcpy(h_results, d_results, size, cudaMemcpyDeviceToHost);
 cudaMemcpy(h_reduction_result, d_reduction_result, BLOCKS * sizeof(float), cudaMemcpyDeviceToHost);

 // ================================================
 // STEP 7: CPU - Final reduction and display
 // ================================================
 printf("[CPU] Performing final reduction...\n");
 float total_sum = 0.0f;
 for (int i = 0; i < BLOCKS; i++) {
 total_sum += h_reduction_result[i];
 }

 printf("\n================================================\n");
 printf(" RESULTS\n");
 printf("================================================\n");
 printf(" Total elements processed: %d\n", N);
 printf(" Sum of results: %.6f\n", total_sum);
 printf(" Sample result[0]: %.6f\n", h_results[0]);
 printf(" Sample result[N-1]: %.6f\n", h_results[N-1]);

 // ================================================
 // Cleanup
 // ================================================
 printf("\n[Cleanup] Freeing memory...\n");
 cudaFree(d_data);
 cudaFree(d_results);
 cudaFree(d_reduction_result);
 free(h_data);
 free(h_results);
 free(h_reduction_result);

 cudaEventDestroy(start);
 cudaEventDestroy(stop);

 printf("\n[Complete] Hybrid program finished successfully!\n");

 return 0;
}

/*
 * OpenMP Target Offloading Example
 * Demonstrates portable GPU acceleration using OpenMP 4.5+ target directives
 * Compile: gcc -fopenmp -fopenmp-targets=nvptx64 -o offload offload.c
 * or: gcc -fopenmp -fopenmp-targets=amdgcn-amdhsa -o offload offload.c
 */

#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <time.h>

#define N 1000000
#define EPSILON 1e-6

/*
 * Data structure for simulation particles
 */
typedef struct {
 float position;
 float velocity;
 float acceleration;
} Particle;

/*
 * Initialize particle array on host
 */
void initialize_particles(Particle *particles, int n) {
 #pragma omp parallel for
 for (int i = 0; i < n; i++) {
 particles[i].position = (float)rand() / RAND_MAX * 100.0f;
 particles[i].velocity = (float)rand() / RAND_MAX * 10.0f;
 particles[i].acceleration = 0.0f;
 }
}

/*
 * Compute accelerations using GPU (OpenMP target)
 * This kernel runs on the GPU/accelerator
 */
void compute_accelerations_gpu(Particle *particles, int n, float *forces) {
 #pragma omp target teams distribute parallel for \
 map(to:particles[0:n]) \
 map(tofrom:forces[0:n])
 for (int i = 0; i < n; i++) {
 // Simple physics: force = mass * acceleration
 // Assuming unit mass for simplicity
 float force = -0.1f * particles[i].position; // Spring force
 force -= 0.01f * particles[i].velocity; // Damping
 forces[i] = force;
 }
}

/*
 * Update particle states using GPU (OpenMP target)
 */
void update_particles_gpu(Particle *particles, float *forces, int n, float dt) {
 #pragma omp target teams distribute parallel for \
 map(tofrom:particles[0:n]) \
 map(to:forces[0:n])
 for (int i = 0; i < n; i++) {
 // Euler integration
 particles[i].acceleration = forces[i];
 particles[i].velocity += particles[i].acceleration * dt;
 particles[i].position += particles[i].velocity * dt;
 }
}

/*
 * Compute total energy using GPU reduction
 */
float compute_energy_gpu(Particle *particles, int n) {
 float total_energy = 0.0f;

 #pragma omp target teams distribute parallel for \
 map(to:particles[0:n]) \
 reduction(+:total_energy)
 for (int i = 0; i < n; i++) {
 float kinetic = 0.5f * particles[i].velocity * particles[i].velocity;
 float potential = 0.5f * 0.1f * particles[i].position * particles[i].position;
 total_energy += kinetic + potential;
 }

 return total_energy;
}

/*
 * Simulation step combining acceleration, update, and energy
 */
void simulation_step(Particle *particles, float *forces, int n, float dt) {
 // Step 1: Compute forces (GPU)
 compute_accelerations_gpu(particles, n, forces);

 // Step 2: Update particles (GPU)
 update_particles_gpu(particles, forces, n, dt);

 // Step 3: Compute energy (GPU with reduction)
 float energy = compute_energy_gpu(particles, n);

 if (rand() % 1000 == 0) {
 printf(" Energy: %.6f\n", energy);
 }
}

/*
 * Fallback CPU implementation for comparison
 */
void simulation_step_cpu(Particle *particles, int n, float dt) {
 for (int i = 0; i < n; i++) {
 float force = -0.1f * particles[i].position - 0.01f * particles[i].velocity;
 particles[i].acceleration = force;
 particles[i].velocity += particles[i].acceleration * dt;
 particles[i].position += particles[i].velocity * dt;
 }
}

int main() {
 Particle *particles;
 float *forces;
 int n = N;
 int steps = 100;
 float dt = 0.01f;

 printf("================================================\n");
 printf(" OpenMP Target Offloading - Particle Simulation\n");
 printf("================================================\n\n");

 // Allocate memory
 particles = (Particle*)malloc(n * sizeof(Particle));
 forces = (float*)malloc(n * sizeof(float));

 // Initialize random seed
 srand(42);

 // Initialize particles
 printf("[Host] Initializing %d particles...\n", n);
 initialize_particles(particles, n);

 // ================================================
 // GPU Execution with OpenMP Target
 // ================================================
 printf("\n[GPU] Running simulation with OpenMP target offloading...\n");
 printf(" Particles: %d, Time steps: %d\n\n", n, steps);

 clock_t gpu_start = clock();

 for (int step = 0; step < steps; step++) {
 simulation_step(particles, forces, n, dt);
 }

 clock_t gpu_end = clock();
 double gpu_time = (double)(gpu_end - gpu_start) / CLOCKS_PER_SEC;

 printf("[GPU] Simulation complete!\n");
 printf("[GPU] Time: %.4f seconds\n", gpu_time);

 // ================================================
 // CPU Fallback (for comparison)
 // ================================================
 printf("\n[CPU] Running CPU simulation for comparison...\n");

 // Re-initialize
 initialize_particles(particles, n);

 clock_t cpu_start = clock();

 for (int step = 0; step < steps; step++) {
 simulation_step_cpu(particles, n, dt);
 }

 clock_t cpu_end = clock();
 double cpu_time = (double)(cpu_end - cpu_start) / CLOCKS_PER_SEC;

 printf("[CPU] Simulation complete!\n");
 printf("[CPU] Time: %.4f seconds\n", cpu_time);

 // Performance summary
 printf("\n================================================\n");
 printf(" PERFORMANCE SUMMARY\n");
 printf("================================================\n");
 printf(" CPU Time: %.4f seconds\n", cpu_time);
 printf(" GPU Time: %.4f seconds\n", gpu_time);
 printf(" Speedup: %.2fx\n", cpu_time / gpu_time);
 printf("================================================\n");

 // Cleanup
 free(particles);
 free(forces);

 return 0;
}
